class Solution:
    def maxNiceDivisors(self, primeFactors):
        MOD = 10 ** 9 + 7
        n = primeFactors
        if n == 1:
            return 1
        best = [0] * (n + 1)
        best[0] = 1
        for i in range(1, n + 1):
            b = 1
            for part in range(1, i + 1):
                b = max(b, part * best[i - part])
            best[i] = b
        return best[n] % MOD

