class Solution:
    def maxNiceDivisors(self, primeFactors):
        MOD = 10 ** 9 + 7
        n = primeFactors
        if n <= 3:
            return n % MOD
        q, r = divmod(n, 3)
        if r == 0:
            return pow(3, q, MOD)
        if r == 1:
            return (pow(3, q - 1, MOD) * 4) % MOD
        return (pow(3, q, MOD) * 2) % MOD

