var maxNiceDivisors = function(primeFactors) {
    const MOD = 1000000007n;
    const n = BigInt(primeFactors);
    if (primeFactors <= 3) return primeFactors % 1000000007;
    const modpow = (b, e) => {
        b %= MOD;
        let r = 1n;
        while (e > 0n) {
            if (e & 1n) r = (r * b) % MOD;
            b = (b * b) % MOD;
            e >>= 1n;
        }
        return r;
    };
    const q = n / 3n;
    const r = n % 3n;
    let res;
    if (r === 0n) res = modpow(3n, q);
    else if (r === 1n) res = (modpow(3n, q - 1n) * 4n) % MOD;
    else res = (modpow(3n, q) * 2n) % MOD;
    return Number(res);
};
